    public static boolean isRadicalNumber(int n) {
        return n >= 1 && n <= 214;
    }

    public static String symbol(int n) {
        if (!isRadicalNumber(n)) return "";
        return SYMBOLS[n - 1];
    }

    public static String pinyin(int n) {
        if (!isRadicalNumber(n)) return "";
        return PINYIN[n - 1];
    }

    public static String meaningRu(int n) {
        if (!isRadicalNumber(n)) return "";
        return RU[n - 1];
    }

    public static String audioName(int n) {
        if (!isRadicalNumber(n)) return "";
        return String.format(java.util.Locale.US, "k%03d", n);
    }

    public static int numberBySymbol(String symbol) {
        if (symbol == null) return -1;
        for (int i = 0; i < SYMBOLS.length; i++) {
            if (SYMBOLS[i].equals(symbol)) return i + 1;
        }
        return -1;
    }
